// One email can carry several attachments; fan out to one item per
// usable document. Policy (allowlist, dedup) is NOT decided here — the
// app owns that; this node only reshapes data.
//
// IMPORTANT: attachment bytes are fetched via getBinaryDataBuffer, never
// read from item.binary[key].data directly — depending on n8n's binary
// storage mode, .data can be a reference stub instead of real base64.
const ALLOWED = new Set(['application/pdf', 'image/png', 'image/jpeg', 'image/webp']);
const out = [];
const items = $input.all();
for (let i = 0; i < items.length; i++) {
  const item = items[i];
  const sender =
    item.json.from?.value?.[0]?.address ??
    String(item.json.from ?? '').match(/[\w.+-]+@[\w-]+\.[\w.-]+/)?.[0] ??
    null;
  if (!sender) continue;
  const subject = item.json.subject ?? '(no subject)';
  const messageId = item.json.id;
  for (const key of Object.keys(item.binary ?? {})) {
    const att = item.binary[key];
    if (!ALLOWED.has(att.mimeType)) continue;
    const buffer = await this.helpers.getBinaryDataBuffer(i, key);
    out.push({
      json: {
        fileName: att.fileName ?? `${key}`,
        mimeType: att.mimeType,
        data: buffer.toString('base64'),
        sender,
        subject,
        messageId
      }
    });
  }
}
return out; // empty array = nothing to do, execution ends quietly
